namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that selects the most representative sentences
/// based on word-frequency scoring.
/// </summary>
public class ExtractiveSummarizer : IDocumentSummarizer
{
    private const int MaxSummarySentences = 3;

    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string documentText)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= MaxSummarySentences)
        {
            return string.Join(" ", sentences);
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick top sentences but preserve original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(MaxSummarySentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var sentences = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (SentenceDelimiters.Contains(text[i]))
            {
                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                {
                    sentences.Add(sentence);
                }
                start = i + 1;
            }
        }

        // Capture any trailing text without a sentence delimiter.
        var remaining = text[start..].Trim();
        if (remaining.Length > 0)
        {
            sentences.Add(remaining);
        }

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (freq.TryGetValue(word, out int count))
                {
                    freq[word] = count + 1;
                }
                else
                {
                    freq[word] = 1;
                }
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = TokenizeWords(sentences[i]);
            double score = words.Count == 0
                ? 0
                : words.Sum(w => wordFrequencies.GetValueOrDefault(w)) / (double)words.Count;

            scored.Add((i, score));
        }

        return scored;
    }

    private static List<string> TokenizeWords(string text)
    {
        return text
            .Split(' ', StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', ',', '!', '?', ';', ':', '"', '\'', '(', ')'))
            .Where(w => w.Length > 0)
            .ToList();
    }
}

